import{_ as d,o as t,c as o,a2 as c}from"./chunks/framework.C90q7Ucc.js";const p=JSON.parse('{"title":"功能与测试覆盖审计","description":"","frontmatter":{},"headers":[],"relativePath":"testing/coverage-audit.md","filePath":"testing/coverage-audit.md","lastUpdated":1780753561000}'),r={name:"testing/coverage-audit.md"};function a(i,e,s,n,l,m){return t(),o("div",null,[...e[0]||(e[0]=[c('<h1 id="功能与测试覆盖审计" tabindex="-1">功能与测试覆盖审计 <a class="header-anchor" href="#功能与测试覆盖审计" aria-label="Permalink to &quot;功能与测试覆盖审计&quot;">​</a></h1><p>本文把当前用户可见的 bridge 功能映射到本地测试覆盖和真实飞书 E2E 证据。真实飞书场景组织、当前证据和报告 gate 统一维护在 <a href="./real-feishu/">真实飞书 E2E</a>。</p><p>真实飞书 E2E 不应逐条镜像单元测试，而应通过基础对话 suite 和功能 suite 覆盖高风险、客户端可见的工作流，并在一次运行中收集多项相关断言。诊断、终端和会话控制命令 suite 应按 runtime（<code>codex</code> 和 <code>claude</code>）检查，而不是按完整 provider 矩阵检查；tmux 专属命令需覆盖 Codex tmux 和 Claude 默认 tmux 路径。</p><p>真实飞书 harness 现在暴露 <code>coverageTier</code> 来描述测试结构。<code>mandatory-suite</code> 用于最高优先级长流程；<code>representative-suite</code> 用于在选定 provider 上验证功能丰富的工作流；<code>runtime-compressed-command-check</code> 用于命令密集型检查；<code>legacy-transitional-evidence</code> 用于较旧但仍有诊断价值的拆分 full-matrix 场景，这类场景不应继续驱动新扩张。</p><h2 id="功能面" tabindex="-1">功能面 <a class="header-anchor" href="#功能面" aria-label="Permalink to &quot;功能面&quot;">​</a></h2><table tabindex="0"><thead><tr><th>区域</th><th>用户可见行为</th><th>本地覆盖</th><th>真实飞书覆盖</th></tr></thead><tbody><tr><td>Runtime 路由</td><td>普通 IM 消息进入选定 runtime；Claude 默认走 tmux，slash 命令仍在 bridge 内联处理。</td><td><code>bridge-adapter-runtime.test.ts</code>、<code>interactive-turn-runner.test.ts</code>、<code>session-runtime.test.ts</code></td><td><code>message-only</code>、<code>runtime-message</code> 覆盖 codex-sdk/codex-pty/codex-tmux/claude-pty/claude-sdk；Claude tmux 作为默认路径需补 canonical 证据</td></tr><tr><td>Provider 选择</td><td><code>/provider</code> 和 <code>/p</code> 切换 Codex/Claude `sdk</td><td>pty</td><td>tmux`。</td></tr><tr><td>Session 生命周期</td><td><code>/new</code>、<code>/t</code>、<code>/current</code>、<code>/cd</code>、<code>/clear</code>、<code>/his</code>、<code>/check</code>、重命名和归档流程。</td><td><code>feishu-markdown.test.ts</code> 覆盖 <code>/t</code> CardKit 表格结构；<code>command-dispatch.test.ts</code> 覆盖 <code>/t</code> 默认 20、50/100、Codex/Claude runtime 下拉、用户输入轮数、接管确认、running 拒绝和 Claude archive；<code>bridge-command-e2e.test.ts</code> 覆盖 mock app <code>/t</code> 卡片按钮链；<code>bridge-manager.test.ts</code> 覆盖群删除 Codex/Claude 归档。</td><td><code>session-management</code> harness 已把 <code>/t</code> 纳入命令级飞书文本断言；当前 codex-pty 和 codex-tmux 已有语义 canonical 证据，但这些报告早于 <code>/t</code> 单表卡片，codex-sdk/claude-pty/claude-sdk 也仍需重跑。拆分历史场景在 Codex mirror provider 上有可用历史 canonical 证据；<code>history-suite::codex-tmux</code> 现在是 <code>/his</code> default/raw/msg/limit/json/file、长截断和 B 群空历史隔离的首选代表性 provider 证据。</td></tr><tr><td>Runtime 配置</td><td><code>/model</code>、<code>/mode</code>、<code>/sandbox</code>、<code>/network</code>、<code>/reasoning</code>、全局 <code>/set</code>。</td><td><code>command-dispatch.test.ts</code>、<code>bridge-command-e2e.test.ts</code>、<code>config.test.ts</code></td><td><code>command-state</code> 覆盖 runtime 设置并带命令级飞书文本断言；<code>session-management</code> 覆盖 <code>/set</code></td></tr><tr><td>自动任务</td><td><code>/auto</code> 创建/列表/删除和 auto card 回调。</td><td><code>bridge-command-e2e.test.ts</code>、<code>command-dispatch.test.ts</code></td><td><code>command-state</code> provider 矩阵通过真实飞书消息覆盖创建/列表/删除，并断言 created/list/deleted 文本</td></tr><tr><td>Require-at 策略</td><td><code>/require-at on/off</code> 和非 mention 群消息过滤。</td><td><code>command-dispatch.test.ts</code>、<code>feishu-adapter.test.ts</code>、<code>bridge-command-e2e.test.ts</code></td><td><code>require-at-toggle</code> runtime-neutral 报告</td></tr><tr><td>流式和 mirror 交付</td><td>SDK provider 使用直接 <code>im:</code> 卡片；pty/tmux provider 使用 <code>mirror:</code> 交付，且不重复最终文本；悬挂 mirror identity 按 runtime 清理。</td><td><code>interactive-turn-runner.test.ts</code>、<code>mirror-runtime.test.ts</code>、<code>turn-coordinator.test.ts</code>、<code>bridge-manager.test.ts</code></td><td><code>message-only</code>、<code>runtime-message</code>、<code>command-state</code>、<code>session-management</code> provider gate</td></tr><tr><td>Claude Code 集成</td><td>Claude tmux 默认 provider、Claude pty onboarding/trust setup、CCR 激活、Claude JSONL 身份、Claude SDK query 路径。</td><td><code>claude-tmux-provider.test.ts</code>、<code>claude-pty-provider.test.ts</code>、<code>claude-sdk-provider.test.ts</code>、<code>real-claude-pty-provider.e2e.test.ts</code>、<code>claude-session-jsonl.test.ts</code></td><td>Claude pty 报告使用真实 <code>ccr code</code> + fake backend；Claude SDK 报告使用 CCR-backed SDK env + fake backend；Claude tmux 真实飞书证据待补</td></tr><tr><td>Codex 终端 provider</td><td>Codex pty/tmux 启动、prompt 注入、JSONL mirror 和清理。</td><td><code>codex-tmux-provider.test.ts</code>、<code>real-codex-pty-provider.e2e.test.ts</code>、<code>real-codex-tmux-provider.e2e.test.ts</code>、<code>bridge-command-e2e.test.ts</code></td><td>Codex pty/tmux 报告要求 <code>mirror:</code> 输出和 tmux 清理</td></tr><tr><td>飞书 adapter</td><td>消息发送、卡片更新/完成、reply threading、Markdown/card 渲染、事件过滤。</td><td><code>feishu-adapter.test.ts</code>、<code>feishu-adapter-card-e2e.test.ts</code>、<code>plain-markdown.test.ts</code>、<code>delivery-pipeline.test.ts</code></td><td>所有真实飞书报告都要求逐消息 <code>reply_to</code>；<code>card-forms</code> 覆盖 <code>/new-form</code> 作为 <code>interactive</code> CardKit 表单回复，并带 callback_data 前缀证据；<code>agent-question-forms</code> 覆盖模型生成的 <code>&lt;clk-ask&gt;</code> 问题表单和 <code>clk-agent-question</code> callback 前缀证据；<code>markdown-rendering::codex-pty</code> 和 <code>markdown-rendering::codex-tmux</code> 有最终 Markdown 表格/代码块结构的 canonical 飞书原始内容证据；表单场景尚未触发真实 submit callback 事件</td></tr><tr><td>诊断和清理</td><td>真实 E2E dump、bridge 日志、测试群创建/清理、测试 tmux 清理、过期锁处理。</td><td><code>real-feishu-e2e-harness.test.ts</code>、<code>service-manager.test.ts</code></td><td>每个成功真实飞书报告都 gate 群清理；<code>--create-chat</code> fallback 现在会推断或要求 bot app id，确保 lark-cli user 创建的群仍邀请 bridge bot；tmux 报告 gate 测试 tmux 清理</td></tr><tr><td>UI 和服务管理</td><td>配置 UI 路由、通道配置、服务 start/stop/status、hot update。</td><td><code>ui-*.test.ts</code>、<code>service-manager.test.ts</code>、<code>command-dispatch.test.ts</code></td><td>主要依赖本地覆盖；只有 IM 可见的 hot-update dry-run/log 行为在本地覆盖</td></tr><tr><td>附件和 artifact</td><td>出站 artifact、问题卡片/表单、云文档评论交付。</td><td><code>outbound-artifacts.test.ts</code>、<code>delivery-pipeline.test.ts</code></td><td>尚未由 canonical 真实飞书矩阵覆盖</td></tr></tbody></table><h2 id="当前真实飞书-gate" tabindex="-1">当前真实飞书 Gate <a class="header-anchor" href="#当前真实飞书-gate" aria-label="Permalink to &quot;当前真实飞书 Gate&quot;">​</a></h2><p>只有 harness 在自动 gate 通过后写出非 failure JSON 报告，成功报告才有效。必需 gate 包括：</p><ul><li><code>message_observations_passed</code>：每条已发送飞书消息都有预期的 bot <code>reply_to</code>，或在预期过滤时没有回复。</li><li><code>final_feishu_transcript_present</code>：最终 transcript 包含当前场景聊天中的相关 message id。</li><li><code>required_checks_passed</code>：选定路径的 binding/session/runtime identity/audit/provider 检查满足要求。</li><li><code>provider_output_path</code>：SDK 路径产生直接 <code>im:</code> 输出且没有 <code>mirror:</code>；pty/tmux 路径产生 <code>mirror:</code> 输出。</li><li><code>mirror_final_not_duplicated_in_direct_reply</code>：mirror provider 不把最终模型文本复制到直接状态回复中。</li><li><code>created_chat_cleanup_completed</code> 和 <code>scenario_created_chat_cleanup_completed</code>：harness 创建的聊天和 <code>/new</code> 场景创建的聊天都在成功时删除。</li><li><code>fake_ccr_backend_used</code>：fake CCR 场景证明 fake backend 确实收到模型请求。</li></ul><h2 id="缺口" tabindex="-1">缺口 <a class="header-anchor" href="#缺口" aria-label="Permalink to &quot;缺口&quot;">​</a></h2><p>当前 provider/scenario 矩阵已经较宽，但这些功能区域仍主要依赖本地测试：</p><ul><li>历史边界：空历史、跨聊天隔离、长 transcript 截断和 <code>/his json</code>/<code>/his file</code> 附件现在已有合并的 <code>history-suite::codex-tmux</code> canonical 证据，报告为 <code>histsuite-codex-tmux-live-0858.json</code>。该报告证明组合命令计划和分阶段 A/B 预期，包括同一个 <code>/his</code> 命令字符串在不同阶段对应不同 expectation。较旧拆分场景仍有历史证据和本地回归辅助价值，但默认不应继续驱动完整 provider 矩阵活动。</li><li>非 final 命令回复中的最终文本断言：<code>command-state</code> 现在检查 status/settings/runtime/provider/current-state/auto 命令的语义文本；<code>session-management</code> harness 检查 help/config/new/cd/current/check 命令文本，codex-pty/codex-tmux 已有当前语义通过证据。旧 <code>session-management</code> 报告中的 codex-sdk/claude-pty/claude-sdk 仍只证明遗留 <code>reply_to</code> 证据，必须在新语义 gate 下重跑。一次 live <code>session-management::codex-sdk</code> 重跑证明命令链可以到达飞书和 <code>/his 5</code>，但因为 live bridge 仍为 SDK 发出 mirror stream，canonical provider-output gate 失败。旧 live <code>session-management::codex-tmux</code> 诊断失败已被 <code>session-codex-tmux-semantic-live-0550.json</code> 取代，该报告证明 mirror-stream final observation、<code>/his 5</code> marker、provider path 和双重清理。剩余命令密集型场景还需要对 <code>/clear</code>、<code>/t</code>、<code>/shell</code>、<code>/file</code>、permission 和 card callback 路径做同等处理。</li><li>附件和 artifact：图片/文件入站、出站附件、云文档评论回复路径和权限卡片。<code>card-forms</code> 覆盖命令生成的 <code>/new-form</code> CardKit 表单和 callback_data 前缀；<code>agent-question-forms</code> 现在覆盖 harness 矩阵中模型生成的 <code>&lt;clk-ask&gt;</code> 问题表单。两个场景都尚未证明真实 submit callback 事件。</li><li>飞书渲染：Markdown 表格和 fenced code block 现在已有 <code>markdown-rendering::codex-pty</code> 与 <code>markdown-rendering::codex-tmux</code> canonical 真实飞书通过证据；当前真实飞书 mirror/card transcript 会把 <code>ts</code> fence 规范化为 <code>plain_text</code>，因此 gate 检查代码 fence 保留和规范化后的语言。剩余 Markdown provider 路径、嵌套代码块、工具详情卡片、长流式更新和 mirror 控制通知仍主要依赖本地测试。</li><li>权限和恢复体验：缺少读消息权限、缺少删除权限、缺少事件订阅、bot 不在群里、重复 App 实例争抢。</li><li>服务/UI 操作：setup UI 和 service manager 行为主要依赖本地测试，因为它们不自然地由飞书聊天消息驱动。</li></ul><h2 id="下一批测试切片" tabindex="-1">下一批测试切片 <a class="header-anchor" href="#下一批测试切片" aria-label="Permalink to &quot;下一批测试切片&quot;">​</a></h2><p><code>history-suite::codex-tmux</code> 已有 canonical 证据。下一批高价值切片是 <code>basic-dialogue-suite</code>，作为主要长流程集成测试。它的 harness metadata 和 dry-run plan 已描述一条 cross-provider 对话，本地 session simulator 已覆盖 <code>codex-sdk -&gt; claude-sdk -&gt; codex-tmux -&gt; claude-pty -&gt; codex-pty</code> 上可控的 preload/tool/context/goal/mirror-suppression 检查点。下一步是把该 simulator 接到真实飞书运行，并使用确定性模型输出。命令密集型 suite 应继续按 runtime 压缩。历史 suite 应保持以下 gate 作为回归准则：</p><ol><li>保持跨聊天顺序：外层 <code>/runtime</code>、<code>/p</code>、<code>/new</code>；内层 <code>/runtime</code>、<code>/p</code>、<code>/cd</code>、final chat，然后执行历史命令。</li><li>每个命令都继续要求 <code>reply_to</code>。</li><li>接受新的 canonical 报告前，保持 <code>command-state</code> 和 <code>session-management</code> 语义回复断言与当前命令输出一致。</li><li>要求 <code>history-suite</code> 在 A 群发送明确的短 marker echo prompt，然后要求 <code>/his raw 1</code>、<code>/his</code> 和 <code>/his msg 1</code> 回复包含 final chat marker 和历史标题/limit 文本。</li><li>要求 <code>/his limit 3</code> 包含设置成功文本。</li><li>要求 <code>/his json</code> 和 <code>/his file</code> 回复为带具体飞书 file key 的飞书 file 消息。</li><li>要求空历史回复包含 <code>当前会话还没有历史消息。</code>，并通过 <code>expectedForbiddenTexts</code> 排除前一个聊天的 marker；在空 B 群执行 <code>/his*</code> 前不要做 provider setup，因为 provider 初始化本身会创建历史条目。</li><li>要求长历史回复包含长 prompt 头部 marker 和 ASCII 截断标记 <code>...</code>，并通过 <code>expectedForbiddenTexts</code> 排除尾部 marker。</li><li>对 mirror provider，要求两个 A 群 runtime prompt 都通过 <code>mirror-stream-evidence</code> 被观测，并要求 mirror card 在发送 <code>/his*</code> follow-up 前进入 <code>completed</code>；不要要求 prompt 本身有 direct <code>reply_to</code>。</li><li>要求最终报告证明 tmux <code>mirror:</code> provider 路径、direct reply 中无最终文本重复，以及外层/A/B 聊天清理。</li><li>考虑真实飞书重跑前，先运行脚本 typecheck、harness 单元测试和项目 typecheck。</li></ol>',15)])])}const h=d(r,[["render",a]]);export{p as __pageData,h as default};
